import requests
from typing import Optional

class WeatherClient:
    def __init__(self, api_key: str, base_url: str = "https://api.weather.example.com"):
        self.session = requests.Session()
        self.session.headers.update({"Authorization": f"Bearer {api_key}"})
        self.base_url = base_url

    def get_current(self, city: str) -> dict:
        resp = self.session.get(f"{self.base_url}/current", params={"city": city})
        resp.raise_for_status()
        return resp.json()

    def get_forecast(self, city: str, days: int = 5) -> list[dict]:
        resp = self.session.get(f"{self.base_url}/forecast", params={"city": city, "days": days})
        resp.raise_for_status()
        return resp.json()["daily"]

    def get_bulk(self, cities: list[str]) -> dict[str, dict]:
        results = {}
        for city in cities:
            results[city] = self.get_current(city)
        return results

    def close(self):
        self.session.close()
